 30 static bool tryToImproveAlign(
 31     const DataLayout &DL, Instruction *I,
 32     function_ref<Align(Value *PtrOp, Align OldAlign, Align PrefAlign)> Fn) {
 33 
 34   if (auto *PtrOp = getLoadStorePointerOperand(I)) {
 35     Align OldAlign = getLoadStoreAlignment(I);
 36     Align PrefAlign = DL.getPrefTypeAlign(getLoadStoreType(I));
 37 
 38     Align NewAlign = Fn(PtrOp, OldAlign, PrefAlign);
 39     if (NewAlign > OldAlign) {
 40       setLoadStoreAlignment(I, NewAlign);
 41       return true;
 42     }
 43   }
 44 
 45   Value *PtrOp;
 46   const APInt *Const;
 47   if (match(I, m_And(m_PtrToIntOrAddr(m_Value(PtrOp)), m_APInt(Const)))) {
 48     Align ActualAlign = Fn(PtrOp, Align(1), Align(1));
 49     if (Const->ult(ActualAlign.value())) {
 50       I->replaceAllUsesWith(Constant::getNullValue(I->getType()));
 51       return true;
 52     }
 53     if (Const->uge(
 54             APInt::getBitsSetFrom(Const->getBitWidth(), Log2(ActualAlign)))) {
 55       I->replaceAllUsesWith(I->getOperand(0));
 56       return true;
 57     }
 58   }
 59   if (match(I, m_Trunc(m_PtrToIntOrAddr(m_Value(PtrOp))))) {
 60     Align ActualAlign = Fn(PtrOp, Align(1), Align(1));
 61     if (Log2(ActualAlign) >= I->getType()->getScalarSizeInBits()) {
 62       I->replaceAllUsesWith(Constant::getNullValue(I->getType()));
 63       return true;
 64     }
 65   }
 66 
 67   IntrinsicInst *II = dyn_cast<IntrinsicInst>(I);
 68   if (!II)
 69     return false;
 70 
 71   // TODO: Handle more memory intrinsics.
 72   switch (II->getIntrinsicID()) {
 73   case Intrinsic::masked_load:
 74   case Intrinsic::masked_store: {
 75     unsigned PtrOpIdx = II->getIntrinsicID() == Intrinsic::masked_load ? 0 : 1;
 76     Value *PtrOp = II->getArgOperand(PtrOpIdx);
 77     Type *Type = II->getIntrinsicID() == Intrinsic::masked_load
 78                      ? II->getType()
 79                      : II->getArgOperand(0)->getType();
 80 
 81     Align OldAlign = II->getParamAlign(PtrOpIdx).valueOrOne();
 82     Align PrefAlign = DL.getPrefTypeAlign(Type);
 83     Align NewAlign = Fn(PtrOp, OldAlign, PrefAlign);
 84     if (NewAlign <= OldAlign)
 85       return false;
 86 
 87     II->addParamAttr(PtrOpIdx,
 88                      Attribute::getWithAlignment(II->getContext(), NewAlign));
 89     return true;
 90   }
 91   default:
 92     return false;
 93   }
 94 }
